package com.ecoPedal.backend.repository;import com.ecoPedal.backend.entity.Echange;import org.springframework.data.jpa.repository.JpaRepository;import org.springframework.stereotype.Repository;import java.util.List;@Repositorypublic interface EchangeRepository extends JpaRepository<Echange, Long> {    List<Echange> findByUtilisateurId(Long utilisateurId);    List<Echange> findByRecompenseId(Long recompenseId);}